"use strict";parserFactory.register("kobatochan.com",()=>new KobatochanParser);class KobatochanParser extends WordpressBaseParser{constructor(){super()}fetchChapter(e){return HttpClient.wrapFetch(e).then(e=>{let t=e.responseXML,r=KobatochanParser.findAdditionalPageUrls(t);return KobatochanParser.removePaginationElements(t),this.fetchAdditionalPages(t,r.reverse())})}static findAdditionalPageUrls(e){let t=[];for(let r of e.querySelectorAll("div.pgntn-page-pagination-block a"))t.includes(r.href)||t.push(r.href);return t}fetchAdditionalPages(e,t){return 0===t.length?Promise.resolve(e):HttpClient.wrapFetch(t.pop()).then(r=>{let n=r.responseXML;KobatochanParser.removePaginationElements(n);let a=this.findContent(e),i=this.findContent(n);for(let e of[...i.childNodes])a.appendChild(e);return this.fetchAdditionalPages(e,t)})}static removePaginationElements(e){return util.removeChildElementsMatchingSelector(e,"div.page-link, div.pgntn-multipage, div.g-dyn")}}